function e(e){e.querySelectorAll(`[data-copy-button]`).forEach(e=>{e.addEventListener(`click`,async()=>{let t=e.dataset.copyTarget,n=e.dataset.copyText;if(!n&&t){let e=document.getElementById(t);n=e?.textContent||e?.innerText||``}if(n)try{await navigator.clipboard.writeText(n.trim());let t=e.querySelector(`.copy-text`);if(t){let e=t.textContent;t.textContent=`Copie!`,setTimeout(()=>{t.textContent=e},2e3)}}catch(e){console.error(`Erreur lors de la copie:`,e)}})})}export{e as default};